SELECT l.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, cd_lr.code_label AS result_cd_nm FROM mbh_member_login_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN mb_member mem ON mem.member_id = l.member_id LEFT JOIN sy_code cd_lr ON cd_lr.code_grp = 'LOGIN_RESULT' AND cd_lr.code_value = l.result_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

